1	"""
2	Helper for running LibreOffice (soffice) in environments where AF_UNIX
3	sockets may be blocked (e.g., sandboxed VMs).  Detects the restriction
4	at runtime and applies an LD_PRELOAD shim if needed.
5	
6	Usage:
7	    from office.soffice import run_soffice, get_soffice_env
8	
9	    # Option 1 – run soffice directly
10	    result = run_soffice(["--headless", "--convert-to", "pdf", "input.docx"])
11	
12	    # Option 2 – get env dict for your own subprocess calls
13	    env = get_soffice_env()
14	    subprocess.run(["soffice", ...], env=env)
15	"""
16	
17	import os
18	import socket
19	import subprocess
20	import tempfile
21	from pathlib import Path
22	
23	
24	def get_soffice_env() -> dict:
25	    env = os.environ.copy()
26	    env["SAL_USE_VCLPLUGIN"] = "svp"
27	
28	    if _needs_shim():
29	        shim = _ensure_shim()
30	        env["LD_PRELOAD"] = str(shim)
31	
32	    return env
33	
34	
35	def run_soffice(args: list[str], **kwargs) -> subprocess.CompletedProcess:
36	    env = get_soffice_env()
37	    return subprocess.run(["soffice"] + args, env=env, **kwargs)
38	
39	
40	
41	_SHIM_SO = Path(tempfile.gettempdir()) / "lo_socket_shim.so"
42	
43	
44	def _needs_shim() -> bool:
45	    try:
46	        s = socket.socket(socket.AF_UNIX, socket.SOCK_STREAM)
47	        s.close()
48	        return False
49	    except OSError:
50	        return True
51	
52	
53	def _ensure_shim() -> Path:
54	    if _SHIM_SO.exists():
55	        return _SHIM_SO
56	
57	    src = Path(tempfile.gettempdir()) / "lo_socket_shim.c"
58	    src.write_text(_SHIM_SOURCE)
59	    subprocess.run(
60	        ["gcc", "-shared", "-fPIC", "-o", str(_SHIM_SO), str(src), "-ldl"],
61	        check=True,
62	        capture_output=True,
63	    )
64	    src.unlink()
65	    return _SHIM_SO
66	
67	
