69	_SHIM_SOURCE = r"""
70	#define _GNU_SOURCE
71	#include <dlfcn.h>
72	#include <errno.h>
73	#include <signal.h>
74	#include <stdio.h>
75	#include <stdlib.h>
76	#include <sys/socket.h>
77	#include <unistd.h>
78	
79	static int (*real_socket)(int, int, int);
80	static int (*real_socketpair)(int, int, int, int[2]);
81	static int (*real_listen)(int, int);
82	static int (*real_accept)(int, struct sockaddr *, socklen_t *);
83	static int (*real_close)(int);
84	static int (*real_read)(int, void *, size_t);
85	
86	/* Per-FD bookkeeping (FDs >= 1024 are passed through unshimmed). */
87	static int is_shimmed[1024];
88	static int peer_of[1024];
89	static int wake_r[1024];            /* accept() blocks reading this */
90	static int wake_w[1024];            /* close()  writes to this      */
91	static int listener_fd = -1;        /* FD that received listen()    */
92	
93	__attribute__((constructor))
94	static void init(void) {
95	    real_socket     = dlsym(RTLD_NEXT, "socket");
96	    real_socketpair = dlsym(RTLD_NEXT, "socketpair");
97	    real_listen     = dlsym(RTLD_NEXT, "listen");
98	    real_accept     = dlsym(RTLD_NEXT, "accept");
99	    real_close      = dlsym(RTLD_NEXT, "close");
100	    real_read       = dlsym(RTLD_NEXT, "read");
101	    for (int i = 0; i < 1024; i++) {
102	        peer_of[i] = -1;
103	        wake_r[i]  = -1;
104	        wake_w[i]  = -1;
105	    }
106	}
107	
108	/* ---- socket ---------------------------------------------------------- */
109	int socket(int domain, int type, int protocol) {
110	    if (domain == AF_UNIX) {
111	        int fd = real_socket(domain, type, protocol);
112	        if (fd >= 0) return fd;
113	        /* socket(AF_UNIX) blocked – fall back to socketpair(). */
114	        int sv[2];
115	        if (real_socketpair(domain, type, protocol, sv) == 0) {
116	            if (sv[0] >= 0 && sv[0] < 1024) {
117	                is_shimmed[sv[0]] = 1;
118	                peer_of[sv[0]]    = sv[1];
119	                int wp[2];
120	                if (pipe(wp) == 0) {
121	                    wake_r[sv[0]] = wp[0];
122	                    wake_w[sv[0]] = wp[1];
123	                }
124	            }
125	            return sv[0];
126	        }
127	        errno = EPERM;
128	        return -1;
129	    }
130	    return real_socket(domain, type, protocol);
131	}
132	
133	/* ---- listen ---------------------------------------------------------- */
134	int listen(int sockfd, int backlog) {
135	    if (sockfd >= 0 && sockfd < 1024 && is_shimmed[sockfd]) {
136	        listener_fd = sockfd;
137	        return 0;
138	    }
139	    return real_listen(sockfd, backlog);
140	}
141	
142	/* ---- accept ---------------------------------------------------------- */
143	int accept(int sockfd, struct sockaddr *addr, socklen_t *addrlen) {
144	    if (sockfd >= 0 && sockfd < 1024 && is_shimmed[sockfd]) {
145	        /* Block until close() writes to the wake pipe. */
146	        if (wake_r[sockfd] >= 0) {
147	            char buf;
148	            real_read(wake_r[sockfd], &buf, 1);
149	        }
150	        errno = ECONNABORTED;
151	        return -1;
152	    }
153	    return real_accept(sockfd, addr, addrlen);
154	}
155	
156	/* ---- close ----------------------------------------------------------- */
157	int close(int fd) {
158	    if (fd >= 0 && fd < 1024 && is_shimmed[fd]) {
159	        int was_listener = (fd == listener_fd);
160	        is_shimmed[fd] = 0;
161	
162	        if (wake_w[fd] >= 0) {              /* unblock accept() */
163	            char c = 0;
164	            write(wake_w[fd], &c, 1);
165	            real_close(wake_w[fd]);
166	            wake_w[fd] = -1;
167	        }
168	        if (wake_r[fd] >= 0) { real_close(wake_r[fd]); wake_r[fd]  = -1; }
169	        if (peer_of[fd] >= 0) { real_close(peer_of[fd]); peer_of[fd] = -1; }
170	
171	        if (was_listener)
172	            _exit(0);                        /* conversion done – exit */
173	    }
174	    return real_close(fd);
175	}
176	"""
177	
178	
